import React, { useEffect, useRef, useState } from 'react';
import {
  Stage,
  Layer,
  Group,
  Image as KonvaImage,
  Rect,
  Line,
  Circle,
  Ellipse,
  Arrow,
  Transformer,
} from 'react-konva';
import './AnnotationCanvas.css';

/**
 * AnnotationCanvas
 *
 * MAIN CHANGES:
 * 1. The background image is in its own `Group` ("background-group") which is draggable only if
 *    `selectedTool === 'move'`. This group holds the image and a nested "annotation-group".
 * 2. Each annotation shape cancels event bubbling on dragStart (and/or click) so the background
 *    does not move when a shape is dragged.
 * 3. This allows you to pan the background if you click on empty space (while in move mode),
 *    and move shapes individually without also moving the background.
 */

export default function AnnotationCanvas({
  fileUrl,
  annotations,
  onAnnotationsChange,
  selectedTool, // 'move', 'bbox', 'polygon', 'polyline', 'point', 'ellipse'
  scale,
  onWheelZoom,
  activeLabelColor,
  onFinishShape, // called when user finishes drawing a shape => parent can revert tool to "move"
}) {
  const stageRef = useRef(null);
  const containerRef = useRef(null);

  // For bounding boxes & ellipses (transformer)
  const rectRefs = useRef([]);
  const ellipseRefs = useRef([]);
  const transformerRef = useRef(null);

  const [selectedShapeIndex, setSelectedShapeIndex] = useState(null);

  const [dims, setDims] = useState({ width: 0, height: 0 });
  const [konvaImg, setKonvaImg] = useState(null);

  // Position of the background image group
  const [imagePos, setImagePos] = useState({ x: 0, y: 0 });

  // In-progress shapes for drawing
  const [newBox, setNewBox] = useState(null);
  const [tempPoints, setTempPoints] = useState([]);
  const [drawingPolygon, setDrawingPolygon] = useState(false);
  const [tempPolyline, setTempPolyline] = useState([]);
  const [drawingPolyline, setDrawingPolyline] = useState(false);
  const [newEllipse, setNewEllipse] = useState(null);

  // ------------------------------------------------------------------------------------
  // 1) Setup/Resize
  // ------------------------------------------------------------------------------------
  useEffect(() => {
    const handleResize = () => {
      if (containerRef.current) {
        setDims({
          width: containerRef.current.offsetWidth,
          height: containerRef.current.offsetHeight,
        });
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // ------------------------------------------------------------------------------------
  // 2) Load the Image
  // ------------------------------------------------------------------------------------
  useEffect(() => {
    if (!fileUrl) return;
    const img = new Image();
    img.src = fileUrl;
    img.onload = () => {
      setKonvaImg(img);
      // reset image position whenever a new image is loaded
      setImagePos({ x: 0, y: 0 });
    };
    img.onerror = () => console.error('Could not load image:', fileUrl);
  }, [fileUrl]);

  // ------------------------------------------------------------------------------------
  // 3) Utility: Flatten points / bounding box / outside check
  // ------------------------------------------------------------------------------------
  const flattenPoints = (pts) => pts.flatMap((p) => [p.x, p.y]);

  // Return { x1, y1, x2, y2 } bounding box for shape
  const shapeBoundingBox = (ann) => {
    if (ann.type === 'bbox') {
      return {
        x1: ann.x,
        y1: ann.y,
        x2: ann.x + ann.width,
        y2: ann.y + ann.height,
      };
    } else if (ann.type === 'ellipse') {
      return {
        x1: ann.x - ann.radiusX,
        y1: ann.y - ann.radiusY,
        x2: ann.x + ann.radiusX,
        y2: ann.y + ann.radiusY,
      };
    } else if (ann.type === 'polygon' || ann.type === 'polyline') {
      let minX = Infinity,
        minY = Infinity,
        maxX = -Infinity,
        maxY = -Infinity;
      ann.points.forEach((pt) => {
        if (pt.x < minX) minX = pt.x;
        if (pt.y < minY) minY = pt.y;
        if (pt.x > maxX) maxX = pt.x;
        if (pt.y > maxY) maxY = pt.y;
      });
      return { x1: minX, y1: minY, x2: maxX, y2: maxY };
    } else if (ann.type === 'point') {
      return {
        x1: ann.x,
        y1: ann.y,
        x2: ann.x,
        y2: ann.y,
      };
    }
    return null;
  };

  // Check if shape's bounding box is fully outside the image
  const isOutsideImage = (ann) => {
    if (!konvaImg) return false;
    const { x1, y1, x2, y2 } = shapeBoundingBox(ann);
    // Fully outside means bounding box is completely left/above or right/below the image
    if (x2 < 0 || x1 > konvaImg.width || y2 < 0 || y1 > konvaImg.height) {
      return true;
    }
    return false;
  };

  // Convert Stage pointer to local coords for shapes inside background
  const getAnnotationLayerPos = (evt) => {
    const annGroup = stageRef.current?.findOne('#annotation-group');
    if (!annGroup) return null;
    return annGroup.getRelativePointerPosition();
  };

  // ------------------------------------------------------------------------------------
  // 4) Creating new shapes
  // ------------------------------------------------------------------------------------
  // -- BBox --
  const startBox = (pos) => {
    setNewBox({ x: pos.x, y: pos.y, width: 0, height: 0 });
  };
  const updateBox = (pos) => {
    if (!newBox) return;
    setNewBox({
      ...newBox,
      width: pos.x - newBox.x,
      height: pos.y - newBox.y,
    });
  };
  const finalizeBox = () => {
    if (!newBox) return;
    const newAnn = { type: 'bbox', ...newBox, label: '' };
    if (!isOutsideImage(newAnn)) {
      onAnnotationsChange([...annotations, newAnn]);
    }
    setNewBox(null);
    onFinishShape && onFinishShape();
  };

  // -- Polygon --
  const addPolygonPoint = (pos) => {
    setTempPoints((prev) => [...prev, pos]);
    setDrawingPolygon(true);
  };
  const finalizePolygon = () => {
    if (tempPoints.length >= 3) {
      const newAnn = { type: 'polygon', points: tempPoints, label: '' };
      if (!isOutsideImage(newAnn)) {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempPoints([]);
    setDrawingPolygon(false);
    onFinishShape && onFinishShape();
  };

  // -- Polyline --
  const addPolylinePoint = (pos) => {
    setTempPolyline((prev) => [...prev, pos]);
    setDrawingPolyline(true);
  };
  const finalizePolyline = () => {
    if (tempPolyline.length >= 2) {
      const newAnn = { type: 'polyline', points: tempPolyline, label: '' };
      if (!isOutsideImage(newAnn)) {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempPolyline([]);
    setDrawingPolyline(false);
    onFinishShape && onFinishShape();
  };

  // -- Point --
  const addPoint = (pos) => {
    const newAnn = { type: 'point', x: pos.x, y: pos.y, label: '' };
    if (!isOutsideImage(newAnn)) {
      onAnnotationsChange([...annotations, newAnn]);
    }
    onFinishShape && onFinishShape();
  };

  // -- Ellipse --
  const startEllipse = (pos) => {
    setNewEllipse({
      type: 'ellipse',
      x: pos.x,
      y: pos.y,
      radiusX: 0,
      radiusY: 0,
      rotation: 0,
      label: '',
    });
  };
  const updateEllipse = (pos) => {
    if (!newEllipse) return;
    setNewEllipse({
      ...newEllipse,
      radiusX: Math.abs(pos.x - newEllipse.x),
      radiusY: Math.abs(pos.y - newEllipse.y),
    });
  };
  const finalizeEllipse = () => {
    if (!newEllipse) return;
    if (!isOutsideImage(newEllipse)) {
      onAnnotationsChange([...annotations, newEllipse]);
    }
    setNewEllipse(null);
    onFinishShape && onFinishShape();
  };

  // ------------------------------------------------------------------------------------
  // 5) Stage Mouse Events
  // ------------------------------------------------------------------------------------
  const handleMouseDown = (evt) => {
    // If tool = move, do nothing special to create shapes
    if (selectedTool === 'move') return;

    // Clear selection
    setSelectedShapeIndex(null);

    const pos = getAnnotationLayerPos(evt);
    if (!pos) return;

    switch (selectedTool) {
      case 'bbox':
        startBox(pos);
        break;
      case 'polygon':
        addPolygonPoint(pos);
        break;
      case 'polyline':
        addPolylinePoint(pos);
        break;
      case 'point':
        addPoint(pos);
        break;
      case 'ellipse':
        startEllipse(pos);
        break;
      default:
        break;
    }
  };

  const handleMouseMove = (evt) => {
    if (selectedTool === 'bbox' && newBox) {
      const pos = getAnnotationLayerPos(evt);
      if (pos) updateBox(pos);
    } else if (selectedTool === 'ellipse' && newEllipse) {
      const pos = getAnnotationLayerPos(evt);
      if (pos) updateEllipse(pos);
    }
  };

  const handleMouseUp = () => {
    if (selectedTool === 'bbox' && newBox) {
      finalizeBox();
    } else if (selectedTool === 'ellipse' && newEllipse) {
      finalizeEllipse();
    }
  };

  const handleDblClick = () => {
    // Double-click to finalize polygon or polyline
    if (selectedTool === 'polygon' && drawingPolygon) {
      finalizePolygon();
    } else if (selectedTool === 'polyline' && drawingPolyline) {
      finalizePolyline();
    }
  };

  // ------------------------------------------------------------------------------------
  // 6) ESC to Cancel
  // ------------------------------------------------------------------------------------
  useEffect(() => {
    const onCancelAnnotation = () => {
      setNewBox(null);
      setNewEllipse(null);
      setTempPoints([]);
      setTempPolyline([]);
      setDrawingPolygon(false);
      setDrawingPolyline(false);
    };
    window.addEventListener('cancel-annotation', onCancelAnnotation);
    return () => window.removeEventListener('cancel-annotation', onCancelAnnotation);
  }, []);

  // ------------------------------------------------------------------------------------
  // 7) Wheel Zoom
  // ------------------------------------------------------------------------------------
  const handleWheel = (evt) => {
    evt.evt.preventDefault();
    onWheelZoom(evt.evt.deltaY);
  };

  // ------------------------------------------------------------------------------------
  // 8) Transformer (select & transform bounding box or ellipse)
  // ------------------------------------------------------------------------------------
  useEffect(() => {
    const tr = transformerRef.current;
    if (!tr) return;

    const shape = annotations[selectedShapeIndex];
    if (selectedShapeIndex == null || !shape) {
      tr.nodes([]);
      tr.getLayer()?.batchDraw();
      return;
    }

    if (shape.type === 'bbox') {
      const rectNode = rectRefs.current[selectedShapeIndex];
      if (rectNode) {
        tr.nodes([rectNode]);
        tr.rotateEnabled(false); // no rotation for bounding box
      }
    } else if (shape.type === 'ellipse') {
      const ellNode = ellipseRefs.current[selectedShapeIndex];
      if (ellNode) {
        tr.nodes([ellNode]);
        tr.rotateEnabled(true);
      }
    } else {
      // polygons, polylines, points => no transformer
      tr.nodes([]);
    }
    tr.getLayer()?.batchDraw();
  }, [selectedShapeIndex, annotations]);

  // ------------------------------------------------------------------------------------
  // 9) Editable Polygons, Polylines, Points
  // ------------------------------------------------------------------------------------
  function EditablePolygon({ ann, index, color, sc }) {
    const groupRef = useRef(null);

    // Move entire polygon
    const handleGroupDragStart = (e) => {
      // Prevent the background from dragging
      e.cancelBubble = true;
    };
    const handleGroupDragEnd = (e) => {
      const { x, y } = e.target.position();
      // Shift all polygon points by (x, y)
      const movedPoints = ann.points.map((pt) => ({
        x: pt.x + x,
        y: pt.y + y,
      }));
      const updated = [...annotations];
      updated[index] = { ...ann, points: movedPoints };

      // Reset the group's position
      e.target.position({ x: 0, y: 0 });

      // Check if outside
      if (isOutsideImage(updated[index])) {
        updated.splice(index, 1);
      }
      onAnnotationsChange(updated);
    };

    // Move one vertex
    const handleVertexDragMove = (ptIdx, e2) => {
      const { x, y } = e2.target.position();
      const newPoints = [...ann.points];
      newPoints[ptIdx] = { x, y };
      const updated = [...annotations];
      updated[index] = { ...ann, points: newPoints };
      onAnnotationsChange(updated);
    };

    const handleClick = (evt) => {
      evt.cancelBubble = true;
      setSelectedShapeIndex(null);
    };

    // We'll show an arrow from second point to the first => indicating start
    const firstPt = ann.points[0];
    const secondPt = ann.points[1] || { x: firstPt.x + 10, y: firstPt.y };

    return (
      <Group
        ref={groupRef}
        draggable={selectedTool === 'move'}
        onDragStart={handleGroupDragStart}
        onDragEnd={handleGroupDragEnd}
        onClick={handleClick}
      >
        <Line
          points={flattenPoints(ann.points)}
          fill={color + '55'}
          stroke={color}
          strokeWidth={2 / sc}
          closed
        />
        <Arrow
          points={[secondPt.x, secondPt.y, firstPt.x, firstPt.y]}
          fill={color}
          stroke={color}
          strokeWidth={2 / sc}
          pointerLength={10 / sc}
          pointerWidth={8 / sc}
        />

        {/* Draggable vertices */}
        {ann.points.map((pt, i) => (
          <Circle
            key={i}
            x={pt.x}
            y={pt.y}
            radius={6 / sc}
            fill="#fff"
            stroke={color}
            strokeWidth={2 / sc}
            draggable={selectedTool === 'move'}
            onDragStart={(e) => e.cancelBubble = true}
            onDragMove={(e) => handleVertexDragMove(i, e)}
            onClick={(e) => e.cancelBubble = true}
            onMouseEnter={(e) => {
              e.target.getStage().container().style.cursor = 'pointer';
            }}
            onMouseLeave={(e) => {
              e.target.getStage().container().style.cursor = 'default';
            }}
          />
        ))}
      </Group>
    );
  }

  function EditablePolyline({ ann, index, color, sc }) {
    const groupRef = useRef(null);

    const handleGroupDragStart = (e) => {
      e.cancelBubble = true;
    };
    const handleGroupDragEnd = (e) => {
      const { x, y } = e.target.position();
      const movedPoints = ann.points.map((pt) => ({
        x: pt.x + x,
        y: pt.y + y,
      }));
      const updated = [...annotations];
      updated[index] = { ...ann, points: movedPoints };
      e.target.position({ x: 0, y: 0 });

      if (isOutsideImage(updated[index])) {
        updated.splice(index, 1);
      }
      onAnnotationsChange(updated);
    };

    const handleVertexDragMove = (ptIdx, e2) => {
      const { x, y } = e2.target.position();
      const newPoints = [...ann.points];
      newPoints[ptIdx] = { x, y };
      const updated = [...annotations];
      updated[index] = { ...ann, points: newPoints };
      onAnnotationsChange(updated);
    };

    const handleClick = (evt) => {
      evt.cancelBubble = true;
      setSelectedShapeIndex(null);
    };

    const firstPt = ann.points[0];
    const secondPt = ann.points[1] || { x: firstPt.x + 10, y: firstPt.y };

    return (
      <Group
        ref={groupRef}
        draggable={selectedTool === 'move'}
        onDragStart={handleGroupDragStart}
        onDragEnd={handleGroupDragEnd}
        onClick={handleClick}
      >
        <Line
          points={flattenPoints(ann.points)}
          stroke={color}
          strokeWidth={2 / sc}
          closed={false}
        />
        <Arrow
          points={[secondPt.x, secondPt.y, firstPt.x, firstPt.y]}
          fill={color}
          stroke={color}
          strokeWidth={2 / sc}
          pointerLength={10 / sc}
          pointerWidth={8 / sc}
        />

        {/* Draggable vertices */}
        {ann.points.map((pt, i) => (
          <Circle
            key={i}
            x={pt.x}
            y={pt.y}
            radius={6 / sc}
            fill="#fff"
            stroke={color}
            strokeWidth={2 / sc}
            draggable={selectedTool === 'move'}
            onDragStart={(e) => e.cancelBubble = true}
            onDragMove={(e) => handleVertexDragMove(i, e)}
            onClick={(e) => e.cancelBubble = true}
            onMouseEnter={(e) => {
              e.target.getStage().container().style.cursor = 'pointer';
            }}
            onMouseLeave={(e) => {
              e.target.getStage().container().style.cursor = 'default';
            }}
          />
        ))}
      </Group>
    );
  }

  function EditablePoint({ ann, index, color, sc }) {
    const handleDragStart = (e) => {
      e.cancelBubble = true;
    };
    const handleDragEnd = (e) => {
      const { x, y } = e.target.position();
      const updated = [...annotations];
      updated[index] = { ...ann, x, y };
      if (isOutsideImage(updated[index])) {
        updated.splice(index, 1);
      }
      onAnnotationsChange(updated);
    };
    const handleClick = (evt) => {
      evt.cancelBubble = true;
      setSelectedShapeIndex(null);
    };

    return (
      <Circle
        x={ann.x}
        y={ann.y}
        radius={6 / sc}
        fill={color}
        draggable={selectedTool === 'move'}
        onDragStart={handleDragStart}
        onDragEnd={handleDragEnd}
        onClick={handleClick}
        onMouseEnter={(e) => {
          e.target.getStage().container().style.cursor = 'pointer';
        }}
        onMouseLeave={(e) => {
          e.target.getStage().container().style.cursor = 'default';
        }}
      />
    );
  }

  // ------------------------------------------------------------------------------------
  // 10) BBox & Ellipse: transform / drag
  // ------------------------------------------------------------------------------------
  const handleRectDragStart = (e) => {
    e.cancelBubble = true;
  };
  const handleRectDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };
    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  };
  const handleRectTransformEnd = (index, e) => {
    const node = e.target;
    const { x, y } = node.position();
    const width = node.width() * node.scaleX();
    const height = node.height() * node.scaleY();
    node.scaleX(1);
    node.scaleY(1);

    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y, width, height };
    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  };

  const handleEllipseDragStart = (e) => {
    e.cancelBubble = true;
  };
  const handleEllipseDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };
    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  };
  const handleEllipseTransformEnd = (index, e) => {
    const node = e.target;
    const { x, y } = node.position();
    const scaleX = node.scaleX();
    const scaleY = node.scaleY();

    const updated = [...annotations];
    updated[index] = {
      ...updated[index],
      x,
      y,
      radiusX: node.radiusX() * scaleX,
      radiusY: node.radiusY() * scaleY,
      rotation: node.rotation(),
    };
    node.scaleX(1);
    node.scaleY(1);

    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  };

  // ------------------------------------------------------------------------------------
  // 11) Rendering
  // ------------------------------------------------------------------------------------
  const fillColor = activeLabelColor + '55';

  return (
    <div className="canvas-container" ref={containerRef}>
      <Stage
        ref={stageRef}
        width={dims.width}
        height={dims.height}
        scaleX={scale}
        scaleY={scale}
        style={{ background: '#dfe6e9' }}
        onWheel={handleWheel}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onDblClick={handleDblClick}
      >
        <Layer>
          {/* Background group: contains the image and a nested shapes group. 
              Draggable only if in move tool. */}
          <Group
            id="background-group"
            draggable={selectedTool === 'move'}
            x={imagePos.x}
            y={imagePos.y}
            onDragMove={(e) => {
              // Only allow real movement if in "move" tool
              if (selectedTool === 'move') {
                const { x, y } = e.target.position();
                setImagePos({ x, y });
              } else {
                // Otherwise revert to last position
                e.target.position(imagePos);
              }
            }}
            onDragEnd={(e) => {
              const { x, y } = e.target.position();
              setImagePos({ x, y });
            }}
          >
            {/* The image itself */}
            {konvaImg && (
              <KonvaImage
                image={konvaImg}
                width={konvaImg.width}
                height={konvaImg.height}
              />
            )}

            {/* Annotation group: shapes are children so they move with the background,
                but each shape can be dragged individually if in "move" mode. */}
            <Group id="annotation-group">
              {/* Existing shapes */}
              {annotations.map((ann, i) => {
                if (ann.type === 'bbox') {
                  return (
                    <Rect
                      key={i}
                      ref={(node) => {
                        rectRefs.current[i] = node;
                      }}
                      x={ann.x}
                      y={ann.y}
                      width={ann.width}
                      height={ann.height}
                      fill={fillColor}
                      stroke={activeLabelColor}
                      strokeWidth={2 / scale}
                      draggable={selectedTool === 'move'}
                      onClick={(evt) => {
                        evt.cancelBubble = true;
                        setSelectedShapeIndex(i);
                      }}
                      onDragStart={handleRectDragStart}
                      onDragEnd={(evt) => handleRectDragEnd(i, evt)}
                      onTransformEnd={(evt) => handleRectTransformEnd(i, evt)}
                      onMouseEnter={(e) => {
                        e.target.getStage().container().style.cursor = 'move';
                      }}
                      onMouseLeave={(e) => {
                        e.target.getStage().container().style.cursor = 'default';
                      }}
                    />
                  );
                } else if (ann.type === 'polygon') {
                  return (
                    <EditablePolygon
                      key={i}
                      ann={ann}
                      index={i}
                      color={activeLabelColor}
                      sc={scale}
                      selectedTool={selectedTool}
                      annotations={annotations}
                      onAnnotationsChange={onAnnotationsChange}
                      setSelectedShapeIndex={setSelectedShapeIndex}
                      isOutsideImage={isOutsideImage}
                    />
                  );
                } else if (ann.type === 'polyline') {
                  return (
                    <EditablePolyline
                      key={i}
                      ann={ann}
                      index={i}
                      color={activeLabelColor}
                      sc={scale}
                      selectedTool={selectedTool}
                      annotations={annotations}
                      onAnnotationsChange={onAnnotationsChange}
                      setSelectedShapeIndex={setSelectedShapeIndex}
                      isOutsideImage={isOutsideImage}
                    />
                  );
                } else if (ann.type === 'point') {
                  return (
                    <EditablePoint
                      key={i}
                      ann={ann}
                      index={i}
                      color={activeLabelColor}
                      sc={scale}
                      annotations={annotations}
                      onAnnotationsChange={onAnnotationsChange}
                      setSelectedShapeIndex={setSelectedShapeIndex}
                      selectedTool={selectedTool}
                      isOutsideImage={isOutsideImage}
                    />
                  );
                } else if (ann.type === 'ellipse') {
                  return (
                    <Ellipse
                      key={i}
                      ref={(node) => {
                        ellipseRefs.current[i] = node;
                      }}
                      x={ann.x}
                      y={ann.y}
                      radiusX={ann.radiusX}
                      radiusY={ann.radiusY}
                      rotation={ann.rotation || 0}
                      fill={fillColor}
                      stroke={activeLabelColor}
                      strokeWidth={2 / scale}
                      draggable={selectedTool === 'move'}
                      onClick={(evt) => {
                        evt.cancelBubble = true;
                        setSelectedShapeIndex(i);
                      }}
                      onDragStart={handleEllipseDragStart}
                      onDragEnd={(evt) => handleEllipseDragEnd(i, evt)}
                      onTransformEnd={(evt) => handleEllipseTransformEnd(i, evt)}
                      onMouseEnter={(e) => {
                        e.target.getStage().container().style.cursor = 'move';
                      }}
                      onMouseLeave={(e) => {
                        e.target.getStage().container().style.cursor = 'default';
                      }}
                    />
                  );
                }
                return null;
              })}

              {/* In-progress BBox */}
              {newBox && selectedTool === 'bbox' && (
                <Rect
                  x={newBox.x}
                  y={newBox.y}
                  width={newBox.width}
                  height={newBox.height}
                  fill={fillColor}
                  stroke={activeLabelColor}
                  strokeWidth={2 / scale}
                />
              )}

              {/* In-progress Polygon */}
              {drawingPolygon && tempPoints.length > 1 && selectedTool === 'polygon' && (
                <Line
                  points={flattenPoints([...tempPoints, tempPoints[0]])}
                  fill={fillColor}
                  stroke={activeLabelColor}
                  strokeWidth={2 / scale}
                  closed
                />
              )}

              {/* In-progress Polyline */}
              {drawingPolyline && tempPolyline.length > 1 && selectedTool === 'polyline' && (
                <Line
                  points={flattenPoints(tempPolyline)}
                  stroke={activeLabelColor}
                  strokeWidth={2 / scale}
                  closed={false}
                />
              )}

              {/* In-progress Ellipse */}
              {newEllipse && selectedTool === 'ellipse' && (
                <Ellipse
                  x={newEllipse.x}
                  y={newEllipse.y}
                  radiusX={newEllipse.radiusX}
                  radiusY={newEllipse.radiusY}
                  rotation={0}
                  fill={fillColor}
                  stroke={activeLabelColor}
                  strokeWidth={2 / scale}
                />
              )}
            </Group>
          </Group>

          {/* Transformer for bboxes & ellipses only */}
          <Transformer
            ref={transformerRef}
            anchorCornerRadius={4}
            anchorStroke="#00BCD4"
            anchorFill="#00BCD4"
            borderStroke="#00BCD4"
          />
        </Layer>
      </Stage>
    </div>
  );
}
